return $input.all().map(item => {
  // Usa description se existir, senão text_content
  let texto = (item.json.description ?? item.json.text_content ?? item.json.markdown_description ?? "").trim();

  // Regex para CPF (com ou sem pontuação)
  const regexCpf = /\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/g;

  // Regex para telefone (com ou sem DDD, incluindo celulares)
  const regexTelefone = /(\(?\d{2}\)?\s?)?(9?\d{4})-?\d{4}/g;

  // Regex para e-mail
  const regexEmail = /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}\b/g;

  // Regex para endereço
  const regexEndereco = /\b(rua|avenida|av\.?|travessa|estrada|rodovia|alameda)\s+[^\n,\.]*/gi;

  // Regex para RG
  const regexRg = /\b\d{1,2}\.?\d{3}\.?\d{3}-?[0-9xX]\b/g;

  // Regex para CNPJ
  const regexCnpj = /\b\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2}\b/g;

  // Regex para CEP
  const regexCep = /\b\d{5}-?\d{3}\b/g;

  // Aplica anonimização
  texto = texto
    .replace(regexCpf, 'XXX.XXX.XXX-XX')
    .replace(regexRg, 'XX.XXX.XXX-X')
    .replace(regexCnpj, 'XX.XXX.XXX/XXXX-XX')
    .replace(regexTelefone, '(XX) XXXXX-XXXX')
    .replace(regexEmail, 'usuario@exemplo.com')
    .replace(regexEndereco, 'Endereço Anonimizado')
    .replace(regexCep, 'XXXXX-XXX');

  // Retorna o item atualizado mantendo os outros campos
  return {
    json: {
      ...item.json,
      description: texto
    }
  };
});

