// Extrai número do ticket [12345] do título e decide se a descrição é curta
const title = $('Get a task1').first().json.name ;
const descRaw =
  ($json.description ?? $json.text_content ?? $json.body?.description ?? $json.body?.text_content ?? '').trim();

const desc = descRaw.replace(/\s+/g, ' ');
const insufficient = !desc || desc.length < 30; // ajuste o threshold se quiser

const m = title.match(/\[(\d+)\]/);
const ticket_id = m ? m[1] : null;

const comentario = "Com as informações passadas não foi possível identificar o problema. Informe qual é o sistema e descreva detalhadamente o problema, Pois sem essas informações não vamos poder dar andamento ao chamado!";

return [{ json: { ticket_id, insufficient, comentario, title, description: desc } }];

